pub unsafe fn nlrc_payload_drop<T>(ptr: *mut std::ffi::c_void) { std::ptr::drop_in_place(ptr as *mut T); } #[macro_export] macro_rules! nl_ref_common { ($ref:ident, $inner:ident, drop_fn = $drop:path) => { #[repr(transparent)] pub struct $ref { ptr: ::std::ptr::NonNull<$inner>, _marker: ::std::marker::PhantomData<$inner> } impl $ref { pub fn strong_count(this: &Self) -> usize { unsafe { (*this.ptr.as_ptr()).refcount.load(::std::sync::atomic::Ordering::Acquire) } } pub fn ptr_eq(a: &Self, b: &Self) -> bool { a.ptr.as_ptr() == b.ptr.as_ptr() } } impl ::std::ops::Drop for $ref { fn drop(&mut self) { unsafe { $drop(self.ptr.as_ptr() as *mut i64) }; } } impl ::std::ops::Deref for $ref { type Target = $inner; fn deref(&self) -> &$inner { unsafe { &*self.ptr.as_ptr() } } } }; }
#[macro_export] macro_rules! define_nlbox { (inner=$inner:ident, ref_ty=$ref:ident, fields={$($fname:ident:$fty:ty),+}, clone_fn=$clone_fn:path, drop_fn=$drop_fn:path, layout_asserts={$($la_tt:tt)*}) => { #[repr(C)] pub struct $inner { $(pub $fname: $fty,)+ pub refcount: ::std::sync::atomic::AtomicUsize } crate::nl_ref_common!($ref, $inner, drop_fn = $drop_fn); impl $inner { pub(crate) const DROP_FN: unsafe fn(*mut ::std::ffi::c_void) = crate::eval::nlrc::nlrc_payload_drop::<$inner>; } impl $ref { pub fn new($($fname: $fty),+) -> $ref { let ptr = ::std::ptr::NonNull::from(Box::leak(Box::new($inner { $($fname,)+ refcount: ::std::sync::atomic::AtomicUsize::new(1) }))); $ref { ptr, _marker: ::std::marker::PhantomData } } } impl Clone for $ref { fn clone(&self) -> Self { unsafe { $clone_fn(self.ptr.as_ptr() as *mut i64) }; $ref { ptr: self.ptr, _marker: ::std::marker::PhantomData } } } const _: () = { use ::std::mem::{offset_of, size_of}; assert!(size_of::<::std::sync::atomic::AtomicUsize>() == 8); $($la_tt)* }; }; }
#[macro_export] macro_rules! nlinner_set { ($name:ident, $field:ident, $ty:ty) => { pub unsafe fn $name(&self, val: $ty) { let p = ::std::ptr::addr_of!(self.$field) as *mut $ty; ::std::ptr::drop_in_place(p); ::std::ptr::write(p, val); } }; } #[macro_export] macro_rules! nlinner_with_mut { ($name:ident, $field:ident, $ty:ty) => { pub unsafe fn $name<R>(&self, f: impl FnOnce(&mut $ty) -> R) -> R { f(&mut *(::std::ptr::addr_of!(self.$field) as *mut $ty)) } }; }
macro_rules! drop_inner_extern { ($name:ident, $ty:path) => { #[no_mangle] pub unsafe extern "C" fn $name(box_ptr: *mut i64) -> i64 { <$ty>::DROP_FN(box_ptr as *mut std::ffi::c_void); 1 } }; } drop_inner_extern!(nl_consbox_drop_inner, crate::eval::nlboxes::NlConsBox); drop_inner_extern!(nl_vector_drop_inner, crate::eval::nlboxes::NlVector); drop_inner_extern!(nl_cell_drop_inner, crate::eval::nlboxes::NlCell); drop_inner_extern!(nl_record_drop_inner, crate::eval::nlboxes::NlRecord); drop_inner_extern!(nl_str_drop_inner, crate::eval::nlstr::NlStr); drop_inner_extern!(nl_boolvector_drop_inner, crate::eval::nlboxes::NlBoolVector); drop_inner_extern!(nl_chartable_drop_inner, crate::eval::nlboxes::NlCharTable);
use std::alloc::{self, Layout}; fn nl_layout(s: i64, a: i64) -> Option<Layout> { (s>0&&a>0).then(||Layout::from_size_align(s as usize,a as usize).ok()).flatten() } #[no_mangle] pub unsafe extern "C" fn nl_alloc_bytes(size: i64, align: i64) -> *mut u8 { nl_layout(size,align).map_or(std::ptr::null_mut(),|l|unsafe{alloc::alloc(l)}) } #[no_mangle] pub unsafe extern "C" fn nl_dealloc_bytes(ptr: *mut u8, size: i64, align: i64) { if !ptr.is_null(){if let Some(l)=nl_layout(size,align){unsafe{alloc::dealloc(ptr,l)};}} } use std::sync::atomic::{AtomicBool, AtomicI64, Ordering}; static QUIT_FLAG: AtomicI64 = AtomicI64::new(0); #[cfg(unix)] static SIGINT_INSTALLED: AtomicBool = AtomicBool::new(false); #[no_mangle] pub extern "C" fn nl_quit_flag_ptr() -> *mut i64 { QUIT_FLAG.as_ptr() } pub fn take_quit_flag() -> bool { QUIT_FLAG.swap(0, Ordering::SeqCst) != 0 }
#[cfg(unix)] pub fn install_sigint_handler() { use std::sync::Once; static ONCE: Once = Once::new(); ONCE.call_once(|| unsafe { extern "C" fn handler(_: libc::c_int) { QUIT_FLAG.store(1, Ordering::SeqCst); } let mut sa: libc::sigaction = std::mem::zeroed(); sa.sa_sigaction = handler as *const () as usize; libc::sigemptyset(&mut sa.sa_mask); sa.sa_flags = libc::SA_RESTART; libc::sigaction(libc::SIGINT, &sa, std::ptr::null_mut()); SIGINT_INSTALLED.store(true, Ordering::SeqCst); }); } #[cfg(not(unix))] pub fn install_sigint_handler() {} #[cfg(unix)] pub fn sigint_handler_installed_p() -> bool { SIGINT_INSTALLED.load(Ordering::SeqCst) } #[cfg(not(unix))] pub fn sigint_handler_installed_p() -> bool { false }
#[cfg(test)] mod tests { use super::*; #[test] fn alloc_round_trip() { let p=unsafe{nl_alloc_bytes(64,8)}; assert!(!p.is_null()); unsafe{nl_dealloc_bytes(p,64,8)} } #[test] fn alloc_bad() { for(s,a)in[(32,3),(0,8),(-1,8),(32,0)]{assert!(unsafe{nl_alloc_bytes(s,a)}.is_null());} } #[test] fn alloc_null_aligned() { unsafe{nl_dealloc_bytes(std::ptr::null_mut(),32,8)}; let p=unsafe{nl_alloc_bytes(128,16)}; assert!(!p.is_null()&&p as usize&0xF==0); unsafe{nl_dealloc_bytes(p,128,16)} } }
